import{_ as a,o as e,c as t,ai as _}from"./chunks/framework.B1-4-q7d.js";const f=JSON.parse('{"title":"首届智慧农业创新大赛之巡田无人机赛道获奖作品","description":"","frontmatter":{"sidebar":false,"aside":false,"editLink":false,"lastUpdated":false,"prev":false,"next":false,"title":"首届智慧农业创新大赛之巡田无人机赛道获奖作品","date":"2026-03-11T00:00:00.000Z","source":"农业农村部智慧农业-地方实践","category":"cases","link":"https://www.moa.gov.cn/ztzl/zhnyzxd/dfsj/202603/t20260311_6482172.htm","summary":"农田智能巡检与分析平台\\n一、团队介绍\\n农芯(南京)智慧农业研究院有限公司是一家集智慧农业技术研发、产品创新和产业服务于一体的国家级高新技术企业。主要致力于新一代农业传感器、智能装备、农业大数据智能及农业信息技术产品开发及产业化研究,包括智慧农业/数字乡村发展建设、农业大数据中心建设、优质农产品智慧供应链、智慧烟草农业等业务板块。\\n二、装备亮点\\n一是\\n...\\n","contentHash":"6986579a3043b058118f5d20f2001002","tags":["智慧农业","应用案例"]},"headers":[],"relativePath":"cases/2026-03-11-首届智慧农业创新大赛之巡田无人机赛道获奖作品.md","filePath":"cases/2026-03-11-首届智慧农业创新大赛之巡田无人机赛道获奖作品.md"}'),r={name:"cases/2026-03-11-首届智慧农业创新大赛之巡田无人机赛道获奖作品.md"};function s(n,p,o,l,c,d){return e(),t("div",null,[...p[0]||(p[0]=[_('<h1 id="首届智慧农业创新大赛之巡田无人机赛道获奖作品" tabindex="-1">首届智慧农业创新大赛之巡田无人机赛道获奖作品 <a class="header-anchor" href="#首届智慧农业创新大赛之巡田无人机赛道获奖作品" aria-label="Permalink to &quot;首届智慧农业创新大赛之巡田无人机赛道获奖作品&quot;">​</a></h1><blockquote><p>来源: <a href="https://www.moa.gov.cn/ztzl/zhnyzxd/dfsj/202603/t20260311_6482172.htm" target="_blank" rel="noreferrer">农业农村部智慧农业-地方实践</a><br> 日期: 2026-03-11 摘要: 农田智能巡检与分析平台 一、团队介绍 农芯(南京)智慧农业研究院有限公司是一家集智慧农业技术研发、产品创新和产业服务于一体的国家级高新技术企业。主要致力于新一代农业传感器、智能装备、农业大数据智能及农业信息技术产品开发及产业化研究,包括智慧农业/数字乡村发展建设、农业大数据中心建设、优质农产品智慧供应链、智慧烟草农业等业务板块。 二、装备亮点 一是 ...</p></blockquote><h1 id="农田智能巡检与分析平台" tabindex="-1">农田智能巡检与分析平台 <a class="header-anchor" href="#农田智能巡检与分析平台" aria-label="Permalink to &quot;农田智能巡检与分析平台&quot;">​</a></h1><p>农芯(南京)智慧农业研究院有限公司是一家集智慧农业技术研发、产品创新和产业服务于一体的国家级高新技术企业。主要致力于新一代农业传感器、智能装备、农业大数据智能及农业信息技术产品开发及产业化研究,包括智慧农业/数字乡村发展建设、农业大数据中心建设、优质农产品智慧供应链、智慧烟草农业等业务板块。</p><p>二、装备亮点</p><p>一是配备智能机场、Mavic 3M多光谱版无人机及环境气象站。二是配套行业应用软件平台。涵盖巡田机场及飞机设备管理、巡田航线任务规划、无人机飞行控制、巡田数据回传与处理、巡田影像数据回溯、不同作物关键生育期农情分析等核心功能。三是以多光谱无人机和环境气象站为硬件支撑,集成光谱AI分析算法。实现数据采集与智能分析的一体化处理。</p><p>三、应用场景与成效</p><p>覆盖水稻、小麦、烟草、大豆、玉米、棉花等作物场景,提供种植面积核实、栽植密度核算、土壤墒情监测、作物长势评估、产量评估、表型性状与品质评估等分析及应用服务。</p><p>空天地一体化平台</p><p>依托湖州市南浔区区位、经济与产业的发展优势,以及浙江大学的科技创新与成果转化优势,整合并导入浙大、泛浙大优质科研资源,搭建科技创新平台,开展关键技术研发、科研成果转化、高新技术产业化、人才集聚与培养,以及企业培育孵化等工作,建立政府支持、产学研结合、市场化运作的新型研发机构。</p><p>二、装备亮点</p><p>一是多源数据融合。整合遥感卫星、无人机、物联网设备与软件系统交互数据。二是设备管理平台。管理卫星、无人机和种植园内物联网信息采集设备、智能控制设备、可视化监控设备。三是数据综合分析。对接入的卫星、无人机等产生的数据进行存储、收集、汇总,并结合用户使用行为数据,基地概况数据等进行汇总、综合和分析,并最终进行数据展示。</p><p>三、应用场景与成效</p><p>在高标准农田、现代农业产业园、果园、茶园等场景中得到了广泛应用。在双林镇全域部署4台无人机机巢,实现100平方公里自动监测覆盖,服务于土地管理、粮油保供、资源调查、环境整治、应急救援、土壤管理、植被覆盖、违规用地等十余类场景,推动全镇农业农村数字化、可视化治理。</p><p>芯农伽®智慧农业无人值守机场</p><p>2014年孵化于中国科学院植物所重点生态实验室、空天信息创新研究院数字农业与灾害实验室等科技转化企业。公司以新一代信息技术、地理信息技术与航空航天跨界融合为理念,综合运用大数据、人工智能、云计算、高性能计算、气象、雷达、遥感、地理信息系统、卫星定位导航及数值预报等,构建覆盖星空地网数据获取、处理、承载与可视化的数字地球自主核心技术体系。</p><p>二、装备亮点</p><p>一是构建了“无人机+无人值守机库”一体化作业模式。依托自适应航线规划与自动回收充电技术,实现7×24小时全自动巡检,有效破解传统农业监测效率低、数据滞后的难题。二是融合多光谱传感与自动标定技术。精准获取作物长势、土壤墒情等多维度数据,通过NDVI、LAI等指标实现病虫害预警与产量预估的定量化分析。三是采用边缘与云端协同处理架构。对海量农田数据实现轻量化预处理与AI深度挖掘,为用户提供可视化的农情报告与决策支持。</p><p>三、应用场景与成效</p><p>芯农伽®智慧农业无人值守机场可广泛应用于农业种植全过程监测、病虫害早期预警、土壤墒情分析、水肥优化调控、灾害识别与海量田块快速巡检等场景,支撑时序数据分析与种植决策优化。</p><p>低空农业AI数据生产管理系统</p><p>金华浙农信息技术有限公司成立于2021年,是一家专注于农业智能化领域研发、应用型企业,主要围绕低空农业数据采集、AI农业模型研发与数据生产、数据应用、软件开发的国家高新技术企业。公司汇聚遥感、人工智能、农学等领域专业人才。</p><p>二、装备亮点</p><p>一是构建了低空智能巡查体系。依托大疆机场实现从飞行控制到数据实时回传、AI分析的全自动工作流;二是建立了数据智算模块。通过标准化采集、存储与20余项自研AI模型,实现对多类作物的智能识别与数据资产化处理;三是已形成覆盖15个县市区的规模化应用。归集超4400万亩影像数据,并构建起从数据生产到算法优化的全流程闭环,为农业管理提供持续优化的精准数据支持。</p><p>三、应用场景与成效</p><p>金东区粮油作物AI普查中,通过无人机全域飞行获取高分辨率影像,结合AI技术对油菜、小麦、早稻、单季稻、连作晚稻进行自动化识别与分析,精准获取种植面积和空间分布。AI识别结果将作为补助发放依据,确保政策公平透明,同时为农户提供种植优化建议,推动粮油生产提质增效。</p><p>LG-6101A高端多光谱检测装备</p><p>河南谷锦科技有限公司是一家致力于新型智能传感器研发、制造的高新技术公司,立足于产品研发和地理信息实景三维技术创新,为客户提供整套无人机倾斜摄影采集、激光雷达数据采集及多光谱数据采集的硬件产品及信息技术服务、可见光单元集成定制以及信息技术服务。拥有专业的资格证书和多项自主知识产权,能为用户提供完整的空间地理信息数据采集、处理分析、互联网发布等服务。拥有专业的硬件研发集成团队、野外数据 、采集团队、处理与分析团队、专题地图制作团队。拥有多年各类复杂环境下的空间数据处理与分析经验和地理信息系统(GIS)集成经验。</p><p>二、装备亮点</p><p>一是高精度数据采集。配备6100万像素的多光谱相机,该装备能够高精度采集数据。二是毫秒级图像处理。通过定制化硬件与AI智能化算法的有机结合,可在毫秒级完成图像处理,并输出识别结果,生成农田长势分析图和作物病虫害分析图,构建了从数据采集到目标识别的全流程解决方案。</p><p>三、应用场景与成效</p><p>该装备适用于提升大规模农田管理效率、灵活监测山区复杂地形、农业监测、林业保护、交通巡查、禁毒侦查以及灾后快速评估灾情等多个领域。</p><p><a href="https://www.moa.gov.cn/ztzl/zhnyzxd/dfsj/202603/t20260311_6482172.htm" target="_blank" rel="noreferrer">阅读原文</a></p>',33)])])}const h=a(r,[["render",s]]);export{f as __pageData,h as default};
